import { ORDINAL_DATATYPE } from '../../datatype-constants';
import { Registry } from '../../zc-registry';
import { arrayFind, defined, isUndefined, isObjectPropDefined } from '../../../utils/zcutils';
import { isWithinEncode } from '../is-data-active';
import { legend_helpers } from '../../main-zc-init';
// import { getLegendConfig } from '../../../legend/legend-helper';

export function isWithinSizeEncode(d, chartObj) {
    let scaleComponent = arrayFind(chartObj.scales, _ => _.id === 'z-0'),
        { scale, schema } = scaleComponent,
        { dataType, meta } = schema.data,
        config = legend_helpers.getLegendConfig(scaleComponent.encode, scaleComponent.key, chartObj),
        { nullAs } = config,
        size = chartObj.dataset.getZ(d),
        nullAsCondition = val => {
            if (isUndefined(val)) {
                return defined(nullAs) || (dataType === ORDINAL_DATATYPE && isObjectPropDefined(meta[meta.datatype], 'nullformatting'));
            }

            return true;
        };

    return isWithinEncode(size, 'z', chartObj, scale, config, { condition: nullAsCondition });
}

Registry.setComponent('size.isWithinSizeEncode', isWithinSizeEncode);
